-- ═══════════════════════════════════════════════════════════════════════════
--  LOINC 2.82 lab_services catalogue seed — 1834 ranked active lab terms.
--  Source: loinc.org/downloads (top-2000 ranked, active, order-able terms)
--
--  NOT a Flyway migration. Deliberately lives outside src/main/resources so
--  it is never on the classpath and can never be auto-applied at boot. It is
--  a PER-TENANT operational script: Flyway runs once globally, but this data
--  belongs to one hospital_id at a time, and tenants onboarded later still
--  need it. Run it by hand, per hospital.
--
--  No DDL. Inserts only. Idempotent — re-running is a no-op because
--  (hospital_id, test_code) collisions are skipped via ON CONFLICT DO NOTHING.
--
--  ── USAGE ────────────────────────────────────────────────────────────────
--    psql "$DB_URL" \
--         -v hid=9927f334-f124-40b2-835d-6468af7a5975 \
--         -v mode=dormant \
--         -f labs-backend/db/seeds/seed_lab_services_loinc.sql
--
--  ── mode ─────────────────────────────────────────────────────────────────
--    dormant    (recommended) — insert all 1834 rows with active=false.
--                 Zero blast radius: GET /api/lab-services?activeOnly=true
--                 (PerAnalyteResultEntry, the lab tech's hot path) and
--                 /search (TestPicker) both filter active=true, so neither
--                 changes until an admin deliberately enables a test via
--                 Settings → Lab Services, or via the bulk-activate snippet
--                 in activate_lab_services.sql.
--
--    as_ranked  — honour LOINC's own ranking: 1227 rows active, 607 inactive.
--                 Makes the catalogue immediately searchable, but grows the
--                 unpaginated GET /api/lab-services?activeOnly=true response
--                 from ~47 rows (~35 KB) to ~1274 rows (~900 KB) on every
--                 result-entry screen open. PerAnalyteResultEntry.jsx:190
--                 explicitly assumes "~50 rows each". Only pick this if that
--                 payload has been accepted.
--
--  Activation is NOT re-runnable via this script: once a row exists,
--  ON CONFLICT skips it, so a later re-run with a different mode changes
--  nothing. Toggle in the UI or use activate_lab_services.sql instead.
--
--  ── Hospital-owned fields left NULL/default (LOINC cannot know them) ──────
--    price, gst_rate, tat_minutes, default_container_type, default_additive,
--    default_volume_ml, stability_minutes, fasting_required,
--    requires_authorisation, parent_panel_code, hospital_service_id
-- ═══════════════════════════════════════════════════════════════════════════

\set ON_ERROR_STOP on

BEGIN;

-- Params land in a temp table: psql does NOT interpolate :vars inside
-- dollar-quoted strings, so the guard block below reads them from here.
CREATE TEMP TABLE _seed_ctx ON COMMIT DROP AS
    SELECT :'hid'::uuid AS hospital_id, :'mode'::text AS mode;

-- ── Pre-flight guards ────────────────────────────────────────────────────
DO $guard$
DECLARE
    h uuid;
    m text;
    n bigint;
BEGIN
    SELECT hospital_id, mode INTO h, m FROM _seed_ctx;

    IF m NOT IN ('dormant', 'as_ranked') THEN
        RAISE EXCEPTION 'mode must be "dormant" or "as_ranked" (got "%")', m;
    END IF;

    IF NOT EXISTS (SELECT 1 FROM hospitals WHERE id = h) THEN
        RAISE EXCEPTION 'hospital_id % does not exist in hospitals — typo?', h;
    END IF;

    -- The app lazy-seeds ~47 curated rows (CBC/LFT/RFT/LIPID/THYROID/DIAB/
    -- URINE panels + their child analytes) on the FIRST GET /api/lab-services,
    -- gated on countByHospitalId(hospitalId) == 0 (LabCatalogService.list).
    -- Seeding LOINC into an empty catalogue trips that gate permanently: the
    -- curated panels, their parent_panel_code wiring and prices would never
    -- be created, silently breaking panel expansion in per-analyte entry.
    -- The LOINC set carries zero parent_panel_code rows, so it cannot replace
    -- them. Land the baseline first.
    SELECT count(*) INTO n FROM lab_services WHERE hospital_id = h;
    IF n = 0 THEN
        RAISE EXCEPTION
            'Catalogue for hospital % is empty — the app baseline has not been lazy-seeded yet.%',
            h,
            E'\nOpen Settings → Lab Services once for this hospital (or GET /api/lab-services),'
            || E'\nconfirm ~47 rows exist, then re-run this seed.';
    END IF;

    RAISE NOTICE 'hospital=%  mode=%  existing_rows=%', h, m, n;
END
$guard$;

WITH target AS (
    SELECT hospital_id, mode FROM _seed_ctx
),
