INSERT INTO public.lab_services (hospital_id, test_code, loinc_code, name, aliases, category, discipline, specimen_kind, default_method, default_unit, value_type, is_panel, display_order, active)
SELECT t.hospital_id, s.test_code, s.loinc_code, s.name, s.aliases, s.category, s.discipline, s.specimen_kind, s.default_method, s.default_unit, s.value_type, s.is_panel, s.display_order,
       CASE WHEN t.mode = 'dormant' THEN false ELSE s.active END
FROM seed s CROSS JOIN target t
ON CONFLICT (hospital_id, test_code) DO NOTHING;

COMMIT;

-- ── Post-run verification ────────────────────────────────────────────────
\echo ''
\echo 'Catalogue after seed:'
SELECT count(*)                                  AS total_rows,
       count(*) FILTER (WHERE active)            AS active_rows,
       count(*) FILTER (WHERE NOT active)        AS dormant_rows,
       count(*) FILTER (WHERE loinc_code IS NULL) AS baseline_rows_no_loinc
FROM lab_services
WHERE hospital_id = :'hid'::uuid;
